function nextGeneration(alive: number[][]): number[][] {
  const livingSet = new Set(alive.map(([x, y]) => `${x},${y}`));
  const neighborCounts = new Map<string, number>();

  for (const [x, y] of alive) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const key = `${x + dx},${y + dy}`;
        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
      }
    }
  }

  const result: number[][] = [];
  for (const [key, count] of neighborCounts) {
    const isAlive = livingSet.has(key);
    if (isAlive && (count === 2 || count === 3)) {
      result.push(key.split(",").map(Number));
    } else if (!isAlive && count === 3) {
      result.push(key.split(",").map(Number));
    }
  }

  result.sort((a, b) => a[0] - b[0] || a[1] - b[1]);
  return result;
}

export const simulate = (aliveCells: number[][], steps: number): number[][] => {
  let cells = aliveCells;
  for (let i = 0; i < steps; i++) {
    cells = nextGeneration(cells);
  }
  return cells;
};

